def verify_requirements_file(requirements_path: str) -> bool:
    """Verify the requirements file hasn't been tampered with using a checksum."""
    checksum_path = f"{requirements_path}.sha256"

    if not os.path.exists(checksum_path):
        logger.warning(
            f"No checksum file found at {checksum_path}. "
            "Generate one with: sha256sum requirements.txt > requirements.txt.sha256"
        )
        # In a strict security posture, you should return False here.
        # Allowing continuation with warning for initial setup only.
        return True

    with open(requirements_path, 'rb') as f:
        actual_hash = hashlib.sha256(f.read()).hexdigest()

    with open(checksum_path, 'r') as f:
        # Format: "<hash>  <filename>" or just "<hash>"
        expected_hash = f.read().strip().split()[0]

    if actual_hash != expected_hash:
        logger.error(
            f"Requirements file checksum mismatch!\n"
            f"  Expected: {expected_hash}\n"
            f"  Actual:   {actual_hash}\n"
            "This may indicate tampering. Aborting."
        )
        return False

    logger.info("Requirements file checksum verified successfully.")
    return True


def validate_requirements_content(requirements_path: str) -> bool:
    """Validate that requirements are pinned to exact versions with hashes."""
    issues = []

    with open(requirements_path, 'r') as f:
        for line_num, line in enumerate(f, 1):
            line = line.strip()

            # Skip empty lines and comments
            if not line or line.startswith('#') or line.startswith('-'):
                continue

            # Check for pinned versions (exact pins with ==)
            if '==' not in line:
                issues.append(
                    f"  Line {line_num}: '{line}' - Package must be pinned "
                    f"to an exact version using '=='"
                )

            # Warn if no hash is present
            if '--hash' not in line:
                issues.append(
                    f"  Line {line_num}: '{line}' - Missing --hash for "
                    f"integrity verification"
                )

    if issues:
        logger.warning(
            "Requirements file security issues found:\n" + "\n".join(issues)
        )
        # Return False to enforce strict pinning and hashing
        # For migration period, you might return True with warnings
        return False

    logger.info("All packages are properly pinned with hash verification.")
    return True


def generate_locked_requirements(
    requirements_path: str,
    output_path: Optional[str] = None
) -> bool:
    """
    Generate a locked requirements file with hashes using pip-compile.
    This creates a fully reproducible, hash-verified dependency file.
    """
    if output_path is None:
        output_path = requirements_path.replace('.txt', '.lock.txt')
        if output_path == requirements_path:
            output_path = requirements_path + '.lock'

    logger.info(f"Generating locked requirements with hashes: {output_path}")

    try:
        # First ensure pip-tools is available
        subprocess.check_call(
            [sys.executable, '-m', 'pip', 'install', 'pip-tools'],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE
        )

        subprocess.check_call([
            sys.executable, '-m', 'piptools', 'compile',
            '--generate-hashes',
            '--no-emit-index-url',
            '--output-file', output_path,
            requirements_path
        ])

        logger.info(f"Locked requirements written to {output_path}")
        logger.info(
            "Review and commit this file, then use it for installations."
        )
        return True

    except subprocess.CalledProcessError as e:
        logger.error(f"Failed to generate locked requirements: {e}")
        return False
    except FileNotFoundError:
        logger.error("pip-tools not found. Install with: pip install pip-tools")
        return False


def install_dependencies(
    requirements_path: str = "requirements.txt",
    strict_security: bool = True,
    use_lock_file: bool = True,
    allowed_index_url: Optional[str] = None
) -> bool:
    """
    Install dependencies securely for CI/CD pipelines.

    Security measures:
    - Uses pinned versions (no --upgrade to prevent unexpected changes)
    - Requires hash verification (--require-hashes)
    - Verifies requirements file integrity via checksum
    - Restricts to trusted package index
    - Disables pip cache to avoid cache poisoning in shared CI environments
    """

    # Determine which requirements file to use
    lock_file = requirements_path.replace('.txt', '.lock.txt')
    if use_lock_file and os.path.exists(lock_file):
        install_file = lock_file
        logger.info(f"Using locked requirements file: {lock_file}")
    else:
        install_file = requirements_path
        if use_lock_file:
            logger.warning(
                f"Lock file {lock_file} not found. "
                f"Falling back to {requirements_path}. "
                f"Run with --generate-lock to create one."
            )

    if not os.path.exists(install_file):
        logger.error(f"Requirements file not found: {install_file}")
        return False

    # Step 1: Verify the requirements file hasn't been tampered with
    if not verify_requirements_file(install_file):
        if strict_security:
            logger.error("Aborting: requirements file integrity check failed.")
            return False
        logger.warning("Continuing despite integrity check failure (non-strict mode).")

    # Step 2: Validate that packages are properly pinned with hashes
    has_hashes = validate_requirements_content(install_file)

    # Step 3: Build the pip install command with security flags
    cmd = [
        sys.executable, '-m', 'pip', 'install',
        '-r', install_file,
        # Do NOT use --upgrade: we want exactly the pinned versions
        # for reproducible, secure builds
        '--no-cache-dir',  # Prevent cache poisoning in shared CI
        '--no-deps',  # Don't install unpinned transitive dependencies
    ]

    # Require hash checking if hashes are present in the requirements file
    if has_hashes:
        cmd.append('--require-hashes')
        logger.info("Hash verification enabled for all packages.")
    elif strict_security:
        logger.error(
            "Aborting: strict security mode requires hash-pinned dependencies.\n"
            "Generate a locked requirements file with:\n"
            f"  python {sys.argv[0]} --generate-lock"
        )
        return False

    # Restrict to a trusted package index
    if allowed_index_url:
        cmd.extend(['--index-url', allowed_index_url])
        cmd.append('--no-deps')  # Extra safety: don't auto-resolve from index

    # Optionally restrict to only the specified index (no fallback to PyPI)
    trusted_index = os.environ.get('PIP_TRUSTED_INDEX_URL')
    if trusted_index:
        cmd.extend(['--index-url', trusted_index])
        logger.info(f"Using trusted index: {trusted_index}")

    logger.info(f"Running: {' '.join(cmd)}")

    try:
        result = subprocess.run(
            cmd,
            check=True,
            capture_output=True,
            text=True,
            timeout=600  # 10 minute timeout
        )
        logger.info("Dependencies installed successfully.")
        logger.info(result.stdout)
        return True

    except subprocess.CalledProcessError as e:
        logger.error(f"Dependency installation failed:\n{e.stderr}")
        return False
    except subprocess.TimeoutExpired:
        logger.error("Dependency installation timed out after 600 seconds.")
        return False


def audit_installed_packages() -> bool:
    """Run pip-audit to check for known vulnerabilities in installed packages."""
    logger.info("Running security audit on installed packages...")

    try:
        # Install pip-audit if not present
        subprocess.check_call(
            [sys.executable, '-m', 'pip', 'install', 'pip-audit'],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE
        )

        result = subprocess.run(
            [sys.executable, '-m', 'pip_audit', '--strict', '--format', 'json'],
            capture_output=True,
            text=True,
            timeout=300
        )

        if result.returncode != 0:
            try:
                audit_results = json.loads(result.stdout)
                logger.error("Vulnerabilities found in installed packages:")
                for vuln in audit_results.get('dependencies', []):
                    if vuln.get('vulns'):
                        for v in vuln['vulns']:
                            logger.error(
                                f"  {vuln['name']}=={vuln['version']}: "
                                f"{v['id']} - {v.get('description', 'N/A')}"
                            )
            except (json.JSONDecodeError, KeyError):
                logger.error(f"Audit output:\n{result.stdout}\n{result.stderr}")
            return False

        logger.info("Security audit passed: no known vulnerabilities found.")
        return True

    except FileNotFoundError:
        logger.warning("pip-audit not available. Skipping vulnerability scan.")
        return True
    except subprocess.TimeoutExpired:
        logger.warning("Security audit timed out. Skipping.")
        return True


def update_requirements_checksum(requirements_path: str) -> None:
    """Update the SHA256 checksum file for the requirements file."""
    checksum_path = f"{requirements_path}.sha256"

    with open(requirements_path, 'rb') as f:
        file_hash = hashlib.sha256(f.read()).hexdigest()

    with open(checksum_path, 'w') as f:
        f.write(f"{file_hash}  {os.path.basename(requirements_path)}\n")

    logger.info(f"Checksum written to {checksum_path}")
    logger.info("Commit this file alongside your requirements file.")


